output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?emperor ?emperorLabel ?cause_of_death ?causeLabel((xsd:integer(SUBSTR(STR(?end) , 1 , 5)) - xsd:integer(SUBSTR(STR(?start) , 1 , 5))) AS ?years_reigned) WHERE {
  ?emperor wdt:P31 wd:Q568 .
  ?emperor wdt:P1327 ?start .
  ?emperor wdt:P1328 ?end .
  OPTIONAL {
    ?emperor wdt:P509 ?cause_of_death .
  }
  OPTIONAL {
    ?cause_of_death rdfs:label ?causeLabel .
    FILTER(LANG(?causeLabel) = "en")
  }
  ?emperor rdfs:label ?emperorLabel .
  FILTER(LANG(?emperorLabel) = "en")
}

